export const getDeleteDashboardUrl = (name: string, params?: DeleteDashboardParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/dashboards/${name}?${stringifiedParams}` : `/dashboards/${name}`;
};

export const deleteDashboard = async (
  name: string,
  params?: DeleteDashboardParams,
  options?: RequestInit
): Promise<deleteDashboardResponse> => {
  return customFetch<deleteDashboardResponse>(getDeleteDashboardUrl(name, params), {
    ...options,
    method: 'DELETE',
  });
};

/**
 * partially update the specified Dashboard
 */
export type updateDashboardResponse200 = {
  data: Dashboard;
  status: 200;
};

export type updateDashboardResponse201 = {
  data: Dashboard;
  status: 201;
};

export type updateDashboardResponseSuccess = (updateDashboardResponse200 | updateDashboardResponse201) & {
  headers: Headers;
};
export type updateDashboardResponse = updateDashboardResponseSuccess;

export const getUpdateDashboardUrl = (name: string, params?: UpdateDashboardParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/dashboards/${name}?${stringifiedParams}` : `/dashboards/${name}`;
};

export const updateDashboard = async (
  name: string,
  patch: Patch,
  params?: UpdateDashboardParams,
  options?: RequestInit
): Promise<updateDashboardResponse> => {
  return customFetch<updateDashboardResponse>(getUpdateDashboardUrl(name, params), {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/apply-patch+yaml', ...options?.headers },
    body: JSON.stringify(patch),
  });
};

/**
 * connect GET requests to dto of Dashboard
 */
export type getDashboardDtoResponse200 = {
  data: DashboardWithAccessInfo;
  status: 200;
};

export type getDashboardDtoResponseSuccess = getDashboardDtoResponse200 & {
  headers: Headers;
};
export type getDashboardDtoResponse = getDashboardDtoResponseSuccess;

export const getGetDashboardDtoUrl = (name: string) => {
  return `/dashboards/${name}/dto`;
};

export const getDashboardDto = async (name: string, options?: RequestInit): Promise<getDashboardDtoResponse> => {
  return customFetch<getDashboardDtoResponse>(getGetDashboardDtoUrl(name), {
    ...options,
    method: 'GET',
  });
};
